#include <bits/stdc++.h>
using namespace std;

struct Node {
    int data;
    Node* next;
    Node(int x) {
        data = x;
        next = NULL;
    }
};

Node* reverseList(Node* head) {
    Node *prev = NULL, *curr = head, *next = NULL;

    while(curr != NULL) {
        // Store next
        next = curr->next;

        // Reverse current node's pointer
        curr->next = prev;

        // Move pointers one position ahead
        prev = curr;
        curr = next;
    }

    return prev;
}

// Helper function to create linked list
Node* createList() {
    int x;
    cin >> x;

    if(x == -1) return NULL;

    Node* head = new Node(x);
    Node* curr = head;

    while(true) {
        cin >> x;
        if(x == -1) break;
        curr->next = new Node(x);
        curr = curr->next;
    }

    return head;
}

// Helper function to print list
void printList(Node* head) {
    Node* curr = head;
    while(curr != NULL) {
        cout << curr->data << " ";
        curr = curr->next;
    }
    cout << "-1" << endl;
}

int main() {
    int t;
    cin >> t;

    while(t--) {
        Node* head = createList();
        head = reverseList(head);
        printList(head);
    }

    return 0;
}
